# Capability gap analysis scoring model
from dataclasses import dataclass
from typing import Literal

@dataclass
class Capability:
    name: str
    description: str
    internal_score: float          # 1-5: current internal capability
    vendor_fit_scores: dict        # {"vendor_name": fit_score}
    is_differentiating: bool       # True if this is a source of competitive advantage
    internal_build_months: float   # estimated months to build internally
    vendor_annual_cost_usd: float  # vendor cost at expected production volume

    @property
    def best_vendor_fit(self) -> float:
        return max(self.vendor_fit_scores.values()) if self.vendor_fit_scores else 0

    @property
    def recommendation(self) -> Literal["Build", "Buy", "Partner"]:
        gap = 5 - self.internal_score
        if gap < 1:
            return "Build"  # No gap; internal capability is sufficient
        if self.is_differentiating:
            return "Build" if self.best_vendor_fit < 3 else "Partner"
        if self.best_vendor_fit >= 4:
            return "Buy"
        if self.best_vendor_fit >= 2.5:
            return "Partner"
        return "Build"

# Example capabilities
caps = [
    Capability(
        name="LLM inference routing",
        description="Route requests to appropriate model based on task type",
        internal_score=2,
        vendor_fit_scores={"LiteLLM": 4.5, "Portkey": 4.0},
        is_differentiating=False,
        internal_build_months=3,
        vendor_annual_cost_usd=12000
    ),
    Capability(
        name="Domain entity extraction",
        description="Extract entities specific to our product taxonomy",
        internal_score=1,
        vendor_fit_scores={"Vendor A": 2.0},  # generic NER, poor fit
        is_differentiating=True,
        internal_build_months=4,
        vendor_annual_cost_usd=80000
    ),
]

for cap in caps:
    print(f"{cap.name}: {cap.recommendation} (gap={5-cap.internal_score}, best_vendor={cap.best_vendor_fit})")
